const syncLocks = new Map<string, Promise<void>>();
function enqueueSync(instanceId: string, fn: () => Promise<void>) {
  const prev = syncLocks.get(instanceId) || Promise.resolve();
  const next = prev.then(fn).catch(err => console.error('Sync batch error:', err));
  syncLocks.set(instanceId, next);
  next.finally(() => { if (syncLocks.get(instanceId) === next) syncLocks.delete(instanceId); });
}
